oxy_webhelp_navlinks = {"rcv_rbk_managed_migration_process-d27243e8003":{"topics":[{"title":"Preparing for Rubrik-hosted migration","shortdesc":"<p class=\"shortdesc\">Prepare for a Rubrik-hosted migration by validating source location eligibility,         disabling archival activities, and configuring encryption settings.<\/p>","href":"saas\/rcv_prep_rubrik_hosted_migration.html","attributes":{"data-id":"rcv_prep_rubrik_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_prep_rubrik_hosted_migration-d27243e8014","topics":[]},{"title":"Configuring Rubrik-hosted migration","shortdesc":"<p class=\"shortdesc\">Configure your environment to permit the Rubrik-hosted DataSync service to read data         from AWS S3 or on-premises S3-compatible stores.<\/p>","href":"saas\/rcv_config_rubrik_hosted_migration.html","attributes":{"data-id":"rcv_config_rubrik_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_config_rubrik_hosted_migration-d27243e8025","topics":[]},{"title":"Running Rubrik-hosted migration task","shortdesc":"<p class=\"shortdesc\">After the configuration is finalized, the Rubrik Professional Services team runs the         migration task while you monitor its progress to completion.<\/p>","href":"saas\/rcv_running_rbk_hosted_migration.html","attributes":{"data-id":"rcv_running_rbk_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_running_rbk_hosted_migration-d27243e8036","topics":[]},{"title":"Finalizing Rubrik-hosted migration","shortdesc":"<p class=\"shortdesc\">Finalize the migration by coordinating with the Rubrik Professional Services team to         convert metadata, run conversion commands, and re-enable the archival location.<\/p>","href":"saas\/rcv_finalizing_rbk_hosted_migration.html","attributes":{"data-id":"rcv_finalizing_rbk_hosted_migration"},"menu":{"hasChildren":false},"tocID":"rcv_finalizing_rbk_hosted_migration-d27243e8047","topics":[]}]}};